css:
.wrapper {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  container-type: inline-size;
  height: 100%;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  font-variant-numeric: tabular-nums;
}

/* ---- chart card shell (calm dark surface, hairline border, depth shadow) ---- */
.wrapper .crm-pipeline-seg {
  display: flex;
  flex-direction: column;
  height: 100%;
  max-width: 100%;
  box-sizing: border-box;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 14px 16px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: border-color .16s ease, box-shadow .16s ease;
}

/* interactive affordance — bars filter the page on click; restrained glow, no lift */
.wrapper .crm-pipeline-seg:hover {
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5),
              0 0 24px -10px color-mix(in srgb, var(--accent) 55%, transparent);
}
.wrapper .crm-pipeline-seg:focus-within {
  border-color: color-mix(in srgb, var(--accent) 45%, var(--line));
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5),
              inset 0 0 0 1px color-mix(in srgb, var(--accent) 40%, transparent);
}

/* ---- header: card title + muted units sub, single yellow accent marker ---- */
.wrapper .cps-head {
  display: flex;
  flex-direction: column;
  gap: 3px;
  margin-bottom: 12px;
  min-width: 0;
}
.wrapper .cps-title {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 0;
  min-width: 0;
  font: 800 14px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--ink);
  overflow-wrap: break-word;
}
.wrapper .cps-title::before {
  content: "";
  flex: none;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 10px -2px color-mix(in srgb, var(--accent) 70%, transparent);
}
.wrapper .cps-sub {
  margin: 0;
  min-width: 0;
  font: 500 11px/1.35 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted);
  overflow-wrap: break-word;
}

/* ---- chart canvas (script target: #crmPipelineSegChart) ---- */
.wrapper .cps-canvas {
  flex: 1;
  width: 100%;
  min-width: 0;
  min-height: 220px;
  cursor: pointer;
  border-radius: 8px;
}
.wrapper .cps-canvas:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

/* ---- empty state (script target: #crmPipelineSegEmpty) ---- */
.wrapper .cps-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  color: var(--muted);
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

/* respect reduced-motion preference */
@media (prefers-reduced-motion: reduce) {
  .wrapper .crm-pipeline-seg { transition: none; }
}

/* ---- responsive: the block sizes to its OWN grid cell, not the viewport ----
   Container queries (the .wrapper declares container-type: inline-size above) so the
   layout reacts to the cell width even when the viewport is wide. This block is a single
   chart card — there is no KPI grid / data table / filter bar inside it to collapse; the
   page grid stacks the chart PAIR, and within the block we keep the canvas from
   collapsing and let the header text reflow (type stays on the design scale). */

/* stacked / narrow cell (chart pair collapses to one column at ~720px): keep min-height */
@container (max-width: 720px) {
  .wrapper .crm-pipeline-seg { padding: 14px; }
  .wrapper .cps-canvas { min-height: 220px; }
}

/* narrow cell: tighten padding + header rhythm; the canvas never collapses below 220px */
@container (max-width: 420px) {
  .wrapper .crm-pipeline-seg { padding: 12px; }
  .wrapper .cps-head { margin-bottom: 10px; }
  .wrapper .cps-canvas { min-height: 220px; }
}
